from dataclasses import dataclass, field
from enum import Enum
from typing import List, Dict, Tuple

class ChangeDimension(Enum):
    TASK = "task"           # What people do
    PROCESS = "process"     # How they do it
    TOOL = "tool"           # What they use
    SKILL = "skill"         # What they need to know
    INTERACTION = "interaction"  # How they relate to others

@dataclass
class ImpactScore:
    magnitude: int   # 1 (minor) to 5 (major)
    speed: int       # 1 (gradual) to 5 (rapid)

    def composite(self) -> float:
        """Higher magnitude and higher speed = higher overall impact."""
        return (self.magnitude * 0.6) + (self.speed * 0.4)

@dataclass
class GroupImpact:
    group_name: str
    headcount: int
    current_readiness: int  # 0-100
    scores: Dict[ChangeDimension, ImpactScore] = field(default_factory=dict)

    def overall_impact(self) -> float:
        if not self.scores:
            return 0.0
        return sum(s.composite() for s in self.scores.values()) / len(self.scores)

    def priority_tier(self) -> str:
        impact = self.overall_impact()
        readiness_gap = 100 - self.current_readiness
        score = impact * (readiness_gap / 100)
        if score >= 2.5:
            return "P1"
        if score >= 1.5:
            return "P2"
        return "P3"

    def report(self) -> str:
        lines = [
            f"Group: {self.group_name} ({self.headcount} people)",
            f"Overall impact: {self.overall_impact():.2f}/5.0",
            f"Readiness: {self.current_readiness}%",
            f"Priority tier: {self.priority_tier()}",
            "Dimension scores:",
        ]
        for dim, score in self.scores.items():
            lines.append(f"  {dim.value}: magnitude={score.magnitude}, speed={score.speed}")
        return "\n".join(lines)

# Example usage
group = GroupImpact(
    group_name="Customer Success Managers",
    headcount=120,
    current_readiness=35,
    scores={
        ChangeDimension.TASK: ImpactScore(magnitude=4, speed=4),
        ChangeDimension.PROCESS: ImpactScore(magnitude=3, speed=3),
        ChangeDimension.TOOL: ImpactScore(magnitude=5, speed=4),
        ChangeDimension.SKILL: ImpactScore(magnitude=4, speed=3),
        ChangeDimension.INTERACTION: ImpactScore(magnitude=2, speed=2),
    }
)
print(group.report())
print()

# Multi-group priority matrix
groups = [
    group,
    GroupImpact("Legal Reviewers", 25, 70, {
        ChangeDimension.TASK: ImpactScore(3, 2),
        ChangeDimension.PROCESS: ImpactScore(4, 3),
        ChangeDimension.SKILL: ImpactScore(3, 2),
    }),
    GroupImpact("Data Entry Clerks", 80, 20, {
        ChangeDimension.TASK: ImpactScore(5, 5),
        ChangeDimension.PROCESS: ImpactScore(5, 5),
        ChangeDimension.TOOL: ImpactScore(5, 5),
    }),
]

print("Priority Matrix:")
for g in sorted(groups, key=lambda x: x.priority_tier()):
    print(f"  [{g.priority_tier()}] {g.group_name}: impact={g.overall_impact():.2f}, readiness={g.current_readiness}%")

from dataclasses import dataclass
from typing import List, Dict
from collections import defaultdict

@dataclass
class ImpactSignal:
    source: str        # "helpdesk" | "survey" | "teams" | "interview"
    group: str
    dimension: str     # task | process | tool | skill | interaction
    text: str
    severity: int      # 1-5

def aggregate_signals(signals: List[ImpactSignal]) -> Dict[str, Dict[str, float]]:
    """
    Aggregate impact signals by group and dimension.
    Returns: {group: {dimension: avg_severity}}
    """
    totals: Dict[str, Dict[str, List[int]]] = defaultdict(lambda: defaultdict(list))
    for sig in signals:
        totals[sig.group][sig.dimension].append(sig.severity)

    result = {}
    for group, dims in totals.items():
        result[group] = {
            dim: sum(vals) / len(vals)
            for dim, vals in dims.items()
        }
    return result

def flag_emerging_risks(
    aggregated: Dict[str, Dict[str, float]],
    threshold: float = 3.0
) -> List[str]:
    """Flag group/dimension combinations exceeding severity threshold."""
    flags = []
    for group, dims in aggregated.items():
        for dim, avg in dims.items():
            if avg >= threshold:
                flags.append(f"{group} / {dim}: avg severity {avg:.1f}")
    return flags

# Simulated signals from various sources
signals = [
    ImpactSignal("helpdesk", "Customer Success", "tool", "AI suggestions not showing in CRM", 4),
    ImpactSignal("survey", "Customer Success", "skill", "Unsure how to evaluate AI output quality", 4),
    ImpactSignal("survey", "Customer Success", "skill", "Need more guidance on prompting", 3),
    ImpactSignal("helpdesk", "Legal Review", "process", "Workflow docs do not match new AI step", 5),
    ImpactSignal("interview", "Legal Review", "skill", "Partners unfamiliar with AI accuracy limitations", 3),
]

aggregated = aggregate_signals(signals)
risks = flag_emerging_risks(aggregated, threshold=3.5)

print("Emerging CIA risks (automated signal aggregation):")
for r in risks:
    print(f"  - {r}")
